UPDATE t_erp_fin_invoice
customer_name = #{customerName}, total_amount = #{totalAmount}, settled_amount = #{settledAmount}, status = #{status}, remark = #{remark}, update_by = #{updateBy}, update_time = #{updateTime},
WHERE id = #{id}
